using System;
using System.IO;
using Microsoft.Build.Logging;
using Microsoft.Build.Framework;

class Program
{
    static void Main(string[] args)
    {
        var reader = new BinaryLogReplayEventSource();

        reader.ErrorRaised += (sender, e) =>
        {
            Console.WriteLine($"ERROR [{e.Code}] in {e.ProjectFile}");
            Console.WriteLine($"  File: {e.File}({e.LineNumber},{e.ColumnNumber})");
            Console.WriteLine($"  Message: {e.Message}");
            Console.WriteLine();
        };

        reader.WarningRaised += (sender, e) =>
        {
            if (e.Code != null && (e.Code.StartsWith("NU") || e.Code.StartsWith("MSB")))
            {
                Console.WriteLine($"WARNING [{e.Code}] in {e.ProjectFile}");
                Console.WriteLine($"  Message: {e.Message}");
                Console.WriteLine();
            }
        };

        reader.BuildFinished += (sender, e) =>
        {
            Console.WriteLine($"BUILD {(e.Succeeded ? "SUCCEEDED" : "FAILED")}");
        };

        reader.Replay(args[0]);
    }
}
EOF

